proof_block:
let p_all = forall |i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@;
    let p_strict = forall |i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@;
    let s_hi = self_@[self_.keys@[hi as int]]@ != v@;
    assert((r1.0 == p_all) && (r2.0 == p_all) ==> r1.0 == r2.0);
    assert(!r1.0 && (r1.1 == (s_hi && p_strict)) && !r2.0 && (r2.1 == (s_hi && p_strict)) ==> r1.1 == r2.1);
    assert(({
        &&& (r1.0 == p_all)
        &&& (!r1.0 ==> (r1.1 == (s_hi && p_strict)))
        &&& (r2.0 == p_all)
        &&& (!r2.0 ==> (r2.1 == (s_hi && p_strict)))
    }) ==> det_keys_in_index_range_agree_equal(r1, r2));
